import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"雷神之锤","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/雷神之锤.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/雷神之锤.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/雷神之锤.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"雷神之锤",tabindex:"-1"},[p("雷神之锤 "),r("a",{class:"header-anchor",href:"#雷神之锤","aria-label":'Permalink to "雷神之锤"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌035")])])],-1),n('<h1 id="雷神之锤-1" tabindex="-1">雷神之锤 <a class="header-anchor" href="#雷神之锤-1" aria-label="Permalink to &quot;雷神之锤&quot;">​</a></h1><p>雷神之锤</p><p>本质：神话本质<br> 价格：A+4500<br> 分类：锤<br> 体积：4<br> 武器伤害：28L 附带2点附加成功<br> 武器属性：【重型武器】【双手】【幻灭】【碾压】<br> 描述：<br> 雷神之锤，本名Mjolnir，起源于北欧神话，但本资源中提供的是漫威世界中的雷神托尔所使用的版本。<br> 雷神之锤的锤头以可以附着大量魔法和能量的阿斯加德特产金属—乌鲁金属制造，并且在即将衰退的恒星之中完成锻造，整个锤子的手柄由世界之树的木材制成。<br> 持有雷神之锤的人将获得雷神的力量，但同时，这也意味着不被雷神之锤所承认的人无法举起雷神之锤。<br> 效果：<br> 【雷神之证】：身为雷神的武器，运用这把武器需要你具有坚定的内心和不凡的勇武。要举起并且使用雷神之锤需求角色具有31点以及以上的力量属性，这是针对任何想要举起雷神之锤的存在的一个A级别的祝福来源的效果。<br> 当角色具有14点及以上的武技技能时，举起雷神之锤的力量需求下降5点。<br> 当角色具有21点及以上的决心属性，且正面声望比负面声望高时，举起雷神之锤的力量需求下降5点。<br> 当角色在任意影片获得了传奇评价时，举起雷神之锤的力量需求下降5点。<br> 只要拥有举起雷神之锤的资格，那么你同时也具有兑换雷神之力技能树的资格。<br> 每持有一个雷神之力技能，你的雷神之锤的武器伤害就会提升6L，同时以雷神之锤进行攻击时，你还会额外获得2点附加成功。你最多能反复获得这个增益效果三次。<br> 当你习得了四个及以上的雷神之力技能树下的资源，你在使用雷神之锤进行攻击时，每轮2次，可以将攻击造成的伤害提升一半。<br> 【神锤威力】：作为在恒星之中锻造出来，并且拥有强大魔法力量的神锤，雷神之锤拥有强悍的破坏力和难以抵挡的冲击力。<br> 以雷神之锤进行攻击时，你的攻击具有【幻灭】和【碾压】特性（已记入武器属性）。<br> 你以雷神之锤进行攻击时，可以还具有A级别的祝福来源的击飞效果，对方需要以反射豁免对抗你的击飞效果，并且如果你胜出，则可以将对手向上击飞胜出数米。并且只要你这次击飞效果确实地产生了令对手强制移动的效果，那么这次攻击将会与一次冲撞结合，使得对手需要再进行强韧豁免对抗这次攻击的成功数，并且令其被击退你的胜出米数。<br> 【雷霆缠绕】：雷神之锤可以遵从使用者的意愿而缠绕上破坏力强大的雷霆。<br> 雷神之锤造成的伤害类型为电击伤害和钝击伤害取优。并且以雷神之锤进行的攻击会附带等额的麻痹点数。</p><p>雷神之力技能树：<br> 借助雷神之锤力量可以使出的超能力。下属所有技艺均为内在技艺，会如常给予内在属性。</p><p>雷神飞行<br> 价格：B+2000<br> 描述：借助雷神之锤的力量实现快速的飞行。<br> 效果：只要持有雷神之锤，那么人物就具有机动性为完美的飞行能力。并且每轮一次，人物可以自由动作发动神锤的力量，牵引自己令自己能够进行一次移动。</p><p>风驰雷厉<br> 价格：B+2000<br> 描述：令雷神之锤在自己手中旋转继续能量之后，令神锤与自己同时高速冲出，进行迅猛的突击。<br> 效果：消耗一个整轮动作和1点意志力。人物可以释放风驰雷厉。<br> 风驰雷厉是一次冲锋攻击，这次冲锋所进行的攻击必须是以雷神之锤进行的白刃攻击。这次攻击不会令你受到冲锋减值，并且在进行这一次冲锋攻击时，你的基础速度提升100米。<br> 由于你进行突击时的速度之快，这次攻击附带有A级别的【先制】效果。<br> 在加速的过程中，雷神之锤的冲击力被发挥到了极致，因而这次攻击的伤害提升一半。<br> 若你在使用这一招式的当轮内使用过【神锤投掷】则这次攻击造成的伤害再提升一半，并且此次冲锋攻击无视A级及以下的困难地形效果。</p><p>神锤投掷<br> 价格：B+2000<br> 描述：以力量将雷神之锤高速掷出，打击远处的敌人，之后再将神锤召唤回手中。<br> 效果：消耗一个标准动作和1点意志力。你可以将神锤投掷而出。<br> 神锤投掷是一次投掷攻击，并且必须以雷神之锤为武器，如常采用雷神之锤的武器伤害和特殊效果。<br> 由于神锤进行高速的飞行，在属性带来的投掷基础射程的基础上，这次攻击的射程还将提升20米。同时在进行了这次攻击后，直到雷神之锤再次回到你手上之前，雷神之锤具有【回力】特性。<br> 神锤投掷可以以力量或敏捷作为投掷的主属性，并且遵从属性所带来的射程以及相关效果。<br> 如果你选择力量作为神锤投掷的主属性，那么你这次神锤投掷将会具有强大的冲击力，能够附带等额的剧痛点数以及等额的二档肢体肢体妨碍点数。<br> 如果你选择敏捷作为神锤投掷的主属性，那么你这次神锤投掷将会具有速度极快，令敌人难以防备，从而具有A级别的【措手不及】效果。</p><p>雷霆屏障<br> 价格：B+2000<br> 描述：释放出雷神之锤当中的能量，形成雷霆能量的屏障来抵挡攻击。<br> 效果：消耗一个移动动作，你可以以雷神之锤进行一次白刃格挡。这次格挡不获得格挡防御，而是改为获得力场防御。在此基础上，只要你拥有任何一个除本技能之外的雷神之力技能，那么你的力场防御的数值就提升8点。<br> 在雷霆屏障持续期间，一回合一次，你可以将受到的一次远程攻击的伤害降为一半。</p><p>天神轰击<br> 价格：A+4000<br> 前提：拥有至少三个其他雷神之力技能<br> 描述：将自己的神力和生命力注入神锤引发的强力冲击，能够对广大范围内的敌人造成杀伤。<br> 效果：一日一次，你可以消耗4点意志力，并且对自己造成不可豁免的8点恶性伤害，以一个整轮动作，发动天神轰击。<br> 天神轰击是一次以雷神之锤进行的白刃攻击，如常进行检定。范围是你敏感范围内的所有敌方角色，所有范围内的敌方角色需要以反射豁免应对这一次攻击。<br> 由于天神轰击引发的冲击波具有的恐怖威力，这次攻击将会造成韧性伤害。<br> 同时由于天神轰击中所蕴含的最为纯粹和暴烈的雷霆能够制造出强大的电能场，这次攻击中，雷神之锤所附带的麻痹点数将会变为四档异常点数。并且本次攻击还能够具有A级别的祝福来源（因为电能场产生于雷神之锤自身的神力）的【潮湿】状态，受影响单位需要以反射豁免伤害值以抵消这一负面效果，失败则在三轮内进入潮湿状态。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const f=e(s,[["render",o]]);export{A as __pageData,f as default};
